INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1020, 'OpenAI Fellows Fall 2018', 'We’re now accepting applications for the next cohort of OpenAI Fellows, a program which offers a compensated 6-month apprenticeship in AI research at OpenAI.', 'We’re now accepting applications for the next cohort of OpenAI Fellows, a program which offers a compensated 6-month apprenticeship in AI research at OpenAI.', 14, 'OpenAI Blog', 'https://openai.com/index/openai-fellows', '', 'ai_tech', '["Company", "GPT", "AI", "OpenAI"]', '2018-05-30 07:00:00.000000', '2026-03-16 06:51:03.542061', 'https://openai.com/index/openai-fellows', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1021, 'Gym Retro', 'We’re releasing the full version of Gym Retro, a platform for reinforcement learning research on games. This brings our publicly-released game count from around 70 Atari games and 30 Sega games to over 1,000 games across a variety of backing emulators. We’re also releasing the tool we use to add new games to the platform.', 'We’re releasing the full version of Gym Retro, a platform for reinforcement learning research on games. This brings our publicly-released game count from around 70 Atari games and 30 Sega games to over 1,000 games across a variety of backing emulators. We’re also releasing the tool we use to add new games to the platform.', 14, 'OpenAI Blog', 'https://openai.com/index/gym-retro', '', 'ai_tech', '["GPT", "OpenAI", "AI", "Research"]', '2018-05-25 07:00:00.000000', '2026-03-16 06:51:03.542070', 'https://openai.com/index/gym-retro', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1022, 'AI and compute', 'We’re releasing an analysis showing that since 2012, the amount of compute used in the largest AI training runs has been increasing exponentially with a 3.4-month doubling time (by comparison, Moore’s Law had a 2-year doubling period)[^footnote-correction]. Since 2012, this metric has grown by more than 300,000x (a 2-year doubling period would yield only a 7x increase). Improvements in compute have been a key component of AI progress, so as long as this trend continues, it’s worth preparing for ', 'We’re releasing an analysis showing that since 2012, the amount of compute used in the largest AI training runs has been increasing exponentially with a 3.4-month doubling time (by comparison, Moore’s Law had a 2-year doubling period)[^footnote-correction]. Since 2012, this metric has grown by more than 300,000x (a 2-year doubling period would yield only a 7x increase). Improvements in compute have been a key component of AI progress, so as long as this trend continues, it’s worth preparing for the implications of systems far outside today’s capabilities.', 14, 'OpenAI Blog', 'https://openai.com/index/ai-and-compute', '', 'ai_tech', '["GPT", "OpenAI", "AI", "Research"]', '2018-05-16 07:00:00.000000', '2026-03-16 06:51:03.542080', 'https://openai.com/index/ai-and-compute', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1023, 'AI safety via debate', 'We’re proposing an AI safety technique which trains agents to debate topics with one another, using a human to judge who wins.', 'We’re proposing an AI safety technique which trains agents to debate topics with one another, using a human to judge who wins.', 14, 'OpenAI Blog', 'https://openai.com/index/debate', '', 'ai_tech', '["GPT", "Safety & Alignment", "AI", "OpenAI"]', '2018-05-03 07:00:00.000000', '2026-03-16 06:51:03.542089', 'https://openai.com/index/debate', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1024, 'Evolved Policy Gradients', 'We’re releasing an experimental metalearning approach called Evolved Policy Gradients, a method that evolves the loss function of learning agents, which can enable fast training on novel tasks. Agents trained with EPG can succeed at basic tasks at test time that were outside their training regime, like learning to navigate to an object on a different side of the room from where it was placed during training.', 'We’re releasing an experimental metalearning approach called Evolved Policy Gradients, a method that evolves the loss function of learning agents, which can enable fast training on novel tasks. Agents trained with EPG can succeed at basic tasks at test time that were outside their training regime, like learning to navigate to an object on a different side of the room from where it was placed during training.', 14, 'OpenAI Blog', 'https://openai.com/index/evolved-policy-gradients', '', 'ai_tech', '["GPT", "OpenAI", "AI", "Research"]', '2018-04-18 07:00:00.000000', '2026-03-16 06:51:03.542099', 'https://openai.com/index/evolved-policy-gradients', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1025, 'Gotta Learn Fast: A new benchmark for generalization in RL', '', '', 14, 'OpenAI Blog', 'https://openai.com/index/gotta-learn-fast', '', 'ai_tech', '["GPT", "OpenAI", "AI", "Research"]', '2018-04-10 07:00:00.000000', '2026-03-16 06:51:03.542108', 'https://openai.com/index/gotta-learn-fast', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1026, 'Retro Contest', 'We’re launching a transfer learning contest that measures a reinforcement learning algorithm’s ability to generalize from previous experience.', 'We’re launching a transfer learning contest that measures a reinforcement learning algorithm’s ability to generalize from previous experience.', 14, 'OpenAI Blog', 'https://openai.com/index/retro-contest', '', 'ai_tech', '["GPT", "OpenAI", "AI", "Research"]', '2018-04-05 07:00:00.000000', '2026-03-16 06:51:03.542118', 'https://openai.com/index/retro-contest', 0.0, 0);
