INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1065, 'Faster physics in Python', 'We’re open-sourcing a high-performance Python library for robotic simulation using the MuJoCo engine, developed over our past year of robotics research.', 'We’re open-sourcing a high-performance Python library for robotic simulation using the MuJoCo engine, developed over our past year of robotics research.', 14, 'OpenAI Blog', 'https://openai.com/index/faster-physics-in-python', '', 'ai_tech', '["GPT", "OpenAI", "AI", "Research"]', '2017-06-28 07:00:00.000000', '2026-03-16 06:51:03.542494', 'https://openai.com/index/faster-physics-in-python', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1066, 'Learning from human preferences', 'One step towards building safe AI systems is to remove the need for humans to write goal functions, since using a simple proxy for a complex goal, or getting the complex goal a bit wrong, can lead to undesirable and even dangerous behavior. In collaboration with DeepMind’s safety team, we’ve developed an algorithm which can infer what humans want by being told which of two proposed behaviors is better.', 'One step towards building safe AI systems is to remove the need for humans to write goal functions, since using a simple proxy for a complex goal, or getting the complex goal a bit wrong, can lead to undesirable and even dangerous behavior. In collaboration with DeepMind’s safety team, we’ve developed an algorithm which can infer what humans want by being told which of two proposed behaviors is better.', 14, 'OpenAI Blog', 'https://openai.com/index/learning-from-human-preferences', '', 'ai_tech', '["GPT", "Safety & Alignment", "AI", "OpenAI"]', '2017-06-13 07:00:00.000000', '2026-03-16 06:51:03.542503', 'https://openai.com/index/learning-from-human-preferences', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1067, 'Learning to cooperate, compete, and communicate', 'Multiagent environments where agents compete for resources are stepping stones on the path to AGI. Multiagent environments have two useful properties: first, there is a natural curriculum—the difficulty of the environment is determined by the skill of your competitors (and if you’re competing against clones of yourself, the environment exactly matches your skill level). Second, a multiagent environment has no stable equilibrium: no matter how smart an agent is, there’s always pressure to get sma', 'Multiagent environments where agents compete for resources are stepping stones on the path to AGI. Multiagent environments have two useful properties: first, there is a natural curriculum—the difficulty of the environment is determined by the skill of your competitors (and if you’re competing against clones of yourself, the environment exactly matches your skill level). Second, a multiagent environment has no stable equilibrium: no matter how smart an agent is, there’s always pressure to get smarter. These environments have a very different feel from traditional environments, and it’ll take a lot more research before we become good at them.', 14, 'OpenAI Blog', 'https://openai.com/index/learning-to-cooperate-compete-and-communicate', '', 'ai_tech', '["GPT", "OpenAI", "AI", "Research"]', '2017-06-08 07:00:00.000000', '2026-03-16 06:51:03.542513', 'https://openai.com/index/learning-to-cooperate-compete-and-communicate', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1068, 'UCB exploration via Q-ensembles', '', '', 14, 'OpenAI Blog', 'https://openai.com/index/ucb-exploration-via-q-ensembles', '', 'ai_tech', '["GPT", "OpenAI", "AI", "Research"]', '2017-06-05 07:00:00.000000', '2026-03-16 06:51:03.542523', 'https://openai.com/index/ucb-exploration-via-q-ensembles', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1069, 'OpenAI Baselines: DQN', 'We’re open-sourcing OpenAI Baselines, our internal effort to reproduce reinforcement learning algorithms with performance on par with published results. We’ll release the algorithms over upcoming months; today’s release includes DQN and three of its variants.', 'We’re open-sourcing OpenAI Baselines, our internal effort to reproduce reinforcement learning algorithms with performance on par with published results. We’ll release the algorithms over upcoming months; today’s release includes DQN and three of its variants.', 14, 'OpenAI Blog', 'https://openai.com/index/openai-baselines-dqn', '', 'ai_tech', '["GPT", "OpenAI", "AI", "Research"]', '2017-05-24 07:00:00.000000', '2026-03-16 06:51:03.542533', 'https://openai.com/index/openai-baselines-dqn', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1070, 'Robots that learn', 'We’ve created a robotics system, trained entirely in simulation and deployed on a physical robot, which can learn a new task after seeing it done once.', 'We’ve created a robotics system, trained entirely in simulation and deployed on a physical robot, which can learn a new task after seeing it done once.', 14, 'OpenAI Blog', 'https://openai.com/index/robots-that-learn', '', 'ai_tech', '["GPT", "OpenAI", "AI", "Research"]', '2017-05-16 07:00:00.000000', '2026-03-16 06:51:03.542542', 'https://openai.com/index/robots-that-learn', 0.0, 0);
