INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1112, 'Introducing OpenAI', 'OpenAI is a non-profit artificial intelligence research company. Our goal is to advance digital intelligence in the way that is most likely to benefit humanity as a whole, unconstrained by a need to generate financial return. Since our research is free from financial obligations, we can better focus on a positive human impact.', 'OpenAI is a non-profit artificial intelligence research company. Our goal is to advance digital intelligence in the way that is most likely to benefit humanity as a whole, unconstrained by a need to generate financial return. Since our research is free from financial obligations, we can better focus on a positive human impact.', 14, 'OpenAI Blog', 'https://openai.com/index/introducing-openai', '', 'ai_tech', '["Company", "GPT", "AI", "OpenAI"]', '2015-12-11 08:00:00.000000', '2026-03-16 06:51:03.542967', 'https://openai.com/index/introducing-openai', 0.0, 0);
