INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (1125, 'See the whole picture and find the look with Circle to Search', 'Google Search interface featuring AI-powered tools including an "AI Overview" that breaks down an outfit''s components and a virtual "Try it on" button that visualizes apparel on diverse body types.', '<img src="https://storage.googleapis.com/gweb-uniblog-publish-prod/images/FTL__Try_On_Blog_header.max-600x600.format-webp.webp">We’ve updated Circle to Search so you can now explore multiple items in a single image.', 15, 'Google AI Blog', 'https://blog.google/products-and-platforms/products/search/circle-to-search-february-2026/', 'Harsh Kharbanda', 'ai_tech', '["Shopping", "\u6df1\u5ea6\u5b66\u4e60", "Search", "AI", "Google"]', '2026-02-25 18:00:00.000000', '2026-03-16 06:51:04.999636', 'https://blog.google/products-and-platforms/products/search/circle-to-search-february-2026/', 0.0, 0);
